import{_ as t,o as e,c as p,a7 as a}from"./chunks/framework.BgApuQ2e.js";const o="/images/why-bugs-ruin-everything/Taxonomy-chart2-1024x468.png",n="/images/why-bugs-ruin-everything/outside.png",s="/images/why-bugs-ruin-everything/inside.png",g="/images/why-bugs-ruin-everything/tumblr_m5y7apLjOC1rqfhi2o1_250.gif",i="/images/why-bugs-ruin-everything/calm-1.png",h="/images/why-bugs-ruin-everything/calm-2.png",l="/images/why-bugs-ruin-everything/calm-3.png",u="/images/why-bugs-ruin-everything/freakout-1.png",c="/images/why-bugs-ruin-everything/freakout-2.png",m="/images/why-bugs-ruin-everything/freakout-3.png",w="/images/why-bugs-ruin-everything/freakout-4.png",b="/images/why-bugs-ruin-everything/freakout-5.png",_="/images/why-bugs-ruin-everything/water-bottle-11.png",y="/images/why-bugs-ruin-everything/water-bottle-2.png",f="/images/why-bugs-ruin-everything/water-bottle-3.png",d="/images/why-bugs-ruin-everything/water-bottle-4.png",k="/images/why-bugs-ruin-everything/water-bottle-5.png",v="/images/why-bugs-ruin-everything/inchworm.jpg",j="/images/why-bugs-ruin-everything/Ladybug-300x300.jpg",S="/images/why-bugs-ruin-everything/ball-beetle-300x200.jpg",x="/images/why-bugs-ruin-everything/monarch-caterpillar1-300x218.jpeg",q="/images/why-bugs-ruin-everything/aliens_bugs_04.jpg",B="/images/why-bugs-ruin-everything/Viceroy_Butterfly-300x232.jpg",A="/images/why-bugs-ruin-everything/grasshopper-1-300x152.jpg",T="/images/why-bugs-ruin-everything/Housefly_white_background02-300x200.jpg",I="/images/why-bugs-ruin-everything/ants-300x123.jpg",L="/images/why-bugs-ruin-everything/honeybee-300x214.jpg",R="/images/why-bugs-ruin-everything/Moth-300x211.jpg",C="/images/why-bugs-ruin-everything/moths-on-light-270x300.jpg",H="/images/why-bugs-ruin-everything/lots-moths-300x225.jpg",W="/images/why-bugs-ruin-everything/Large-Mosquito-300x271.jpg",D="/images/why-bugs-ruin-everything/fruit-flies-300x196.jpg",E="/images/why-bugs-ruin-everything/spider1-300x199.jpg",P="/images/why-bugs-ruin-everything/daddy_long_legs_lrg-300x173.jpeg",V="/images/why-bugs-ruin-everything/mosquito-300x223.jpg",F="/images/why-bugs-ruin-everything/dick.jpg",G="/images/why-bugs-ruin-everything/louse-229x300.jpg",J="/images/why-bugs-ruin-everything/bed-bugs-300x199.jpg",M="/images/why-bugs-ruin-everything/Cockroaches1.jpg",U="/images/why-bugs-ruin-everything/centipede-300x182.jpg",N="/images/why-bugs-ruin-everything/spider-on-lamp-300x300.jpg",O="/images/why-bugs-ruin-everything/1277193438_huge-spider-on-the-ceiling.gif",$="/images/why-bugs-ruin-everything/spider-bird-300x225.jpg",K="/images/why-bugs-ruin-everything/spider_ceiling-700252-600x480.jpg",Z="/images/why-bugs-ruin-everything/Animated0204.gif",z="/images/why-bugs-ruin-everything/pinit_fg_en_rect_gray_20.png",or=JSON.parse('{"title":"Why Bugs Ruin Everything","description":"","frontmatter":{"title":"Why Bugs Ruin Everything","titleZh":"为何 bug 毁掉一切","date":"2014-02-04T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/02/why-bugs-ruin-everything.html","slug":"why-bugs-ruin-everything"},"headers":[],"relativePath":"posts/why-bugs-ruin-everything.md","filePath":"posts/why-bugs-ruin-everything.md","lastUpdated":1782886257000}'),Q={name:"posts/why-bugs-ruin-everything.md"};function Y(X,r,rr,tr,er,pr){return e(),p("div",null,[...r[0]||(r[0]=[a('<h1 id="为何-bug-毁掉一切-·-why-bugs-ruin-everything" tabindex="-1">为何 bug 毁掉一切 · Why Bugs Ruin Everything <a class="header-anchor" href="#为何-bug-毁掉一切-·-why-bugs-ruin-everything" aria-label="Permalink to &quot;为何 bug 毁掉一切 · Why Bugs Ruin Everything&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/02/why-bugs-ruin-everything.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/02/why-bugs-ruin-everything.html</a> · 2014-02-04</p></blockquote><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/Taxonomy-chart2.png" target="_blank" rel="noreferrer"><img src="'+o+'" alt="Taxonomy chart"></a></p><p>地球几乎是有史以来最棒的星球。它美得惊心动魄,在宇宙中的位置也堪称完美,而且非常适合它那壮丽多样的动植物在此生存繁衍。</p><p><strong>几乎</strong>是有史以来最棒的星球。</p><p>不幸的是,当你这颗星球最鲜明的定义性特征是一场令人作呕的全球性虫灾时,你就没法当上最棒的星球了。</p><p>在这颗其实<strong>没那么</strong>大的星球上,有 10 百亿亿只虫子,也就是<strong>每个活着的人</strong>摊上 15 亿只,它们占了全世界物种的 80%。</p><p>真是可惜。</p><p>而且不像被虫子占领的公寓或房子,我们没法直接搬走——这是我们永久的处境。</p><p>有人可能会说我在&quot;反应过度&quot;或&quot;矫情得像个小娘炮&quot;,因为我说虫子让生活&quot;基本上不值得过下去&quot;,但我没有。原因如下:</p><p><strong>1) 虫子是微型怪物。</strong></p><p>想象一下任何其他类型生物的放大版。</p><p>一条大鱼还是鱼。一只大鸟是鸵鸟或者别的正常玩意儿。一只大爬行动物?鳄鱼。一只大哺乳动物?熊。都是正常东西。</p><p>你知道什么不正常?一只大昆虫。</p><p>你知道为什么不正常吗?<strong>因为一只大昆虫就是一头怪物,而怪物是不正常的。</strong></p><p>想象一只垃圾桶大小的苍蝇、一只公园长椅大小的蚂蚁、或者一辆汽车大小的蟑螂。除了&quot;怪物&quot;以外你还能用什么词来形容这些东西?</p><p>但就因为虫子个头小,我们就能欣然接受住在一颗有 10 百亿亿只怪物的星球上?</p><p>这是一部恐怖片。</p><p><strong>2) 虫子的行为令人发指。</strong></p><p>是的,它们长得像噩梦,但我和许多其他讲道理的人痛恨虫子的主要原因,是它们的行为方式。</p><p>人类在这颗星球上享有精英地位,似乎除了昆虫以外所有生物都懂这一点。跟几乎所有其他生物不一样,昆虫 A) 完全不尊重人类的个人空间,B) 不懂私有财产的概念,以为不请自来地进入室内是没问题的,而且 C) 显然没收到那份备忘录——人类处于食物链的最顶端,这意味着<strong>没人应该以我们为食</strong>。</p><p>如果虫子能像大家一样遵守规矩,它们真的不会是什么大问题。正是它们对边界那种令人发指的漠视,才让它们如此可鄙。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/outside.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="outside"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/inside.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="inside"></a></p><p>问题出在边界上。没人真的讨厌松鼠。但如果松鼠不待在它们该待的外面,而是动不动就跑进你家、爬上你的墙、趴在你的食物上、钻进你的被窝,那我们都会讨厌松鼠。如果松鼠不像它们本该那样害怕人类,而是隔三差五就往人身上跳、在你睡觉的时候在你身上到处爬,还时不时咬你一口吸你的血,我向你保证,我们所有人都会真的、真的非常讨厌松鼠。</p><p><strong>3) 虫子能让你出丑。</strong></p><p>作为一个怕虫子怕到要命的男的,处境不太妙。</p><p>换成别的丢人恐惧症,你通常只要躲开那个东西就行,没人需要知道它把你吓得多脸色发白、惊慌失措。但正如上面说的,虫子想干什么就干什么,你根本没法决定什么时候遇见、什么时候不遇见它们。所以身为&quot;一遇到虫子就怂得不行的那种男的&quot;,一项关键技能就是要控制住&quot;最初的不自主惊恐反应&quot;,简称 IIHR (initial involuntary horror reaction),也就是你突然发现身上或身边有只大虫子时那种反应。IIHR 大概长这样:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/tumblr_m5y7apLjOC1rqfhi2o1_250.gif" target="_blank" rel="noreferrer"><img src="'+g+'" alt="Scared Baby"></a></p><p>一个人待着的时候看见虫子,我就让 IIHR 尽情释放。我觉得这辈子最让我无地自容的事,可能就是有人把我所有私下 IIHR 时刻剪成一个视频合集,放给大家看。</p><p>但如果周围有人,尤其是有女生在场,克制住最初的惊恐冲动、避免当众上演一场 IIHR,就至关重要了。这么多年下来,我在这方面已经练得挺不错了:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/calm-1.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="calm 1"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/calm-2.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt="calm 2"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/calm-3.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="calm 3"></a></p><p>但有时候一场&quot;虫子事件&quot;实在太突然、太侵犯、太吓人,以至于在你有意识的大脑赶到现场接管局面之前,IIHR 已经发生了,你再也没办法把它收回来:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/freakout-1.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt="freakout 1"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/freakout-2.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt="freakout 2"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/freakout-3.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt="freakout 3"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/freakout-4.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt="freakout 4"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/freakout-5.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt="freakout 5"></a></p><p><strong>4) 虫子会给你留下心理阴影。</strong></p><p>到目前为止,我们已经讨论了虫子事件的前两个等级:</p><p><strong>第 1 级)冒犯性虫子事件</strong>——虫子出现在你家里,趴在墙上或地板上</p><p><strong>第 2 级)极度冒犯性虫子事件</strong>——虫子出现在你床上或身上</p><p>但我们还没触及第三种、也是最致命的一种虫子事件:</p><p><strong>第 3 级)改变人生的虫子事件</strong>——虫子钻进你衣服里或跑进你嘴里</p><p>这种事件会永远改变你。比如,自从 1991 年以来,我就再也没用带吸管的水瓶喝过水。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/water-bottle-11.png" target="_blank" rel="noreferrer"><img src="'+_+'" alt="water bottle 1"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/water-bottle-2.png" target="_blank" rel="noreferrer"><img src="'+y+'" alt="water bottle 2"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/water-bottle-3.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt="water bottle 3"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/water-bottle-4.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt="water bottle 4"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/water-bottle-5.png" target="_blank" rel="noreferrer"><img src="'+k+'" alt="water bottle 5"></a></p><p>为了更好地理解我们面对的敌人,来看看昆虫的五大类别:</p><p>(在这篇文章里,我会把蜘蛛和其他蛛形纲动物也叫做昆虫,尽管它们其实不是昆虫。如果我不加这个小备注,至少会有四个人跑到评论区来教训我,所以先声明在此。)</p><p><strong>滑稽虫</strong></p><p>并不是<em>每一种</em>虫子都在让这个世界变成一个糟糕的居住地。要成为滑稽虫、进入这个唯一的褒义类别,必须严格满足以下标准:</p><ul><li>它们待在户外</li><li>它们很可爱</li><li>它们不咬人</li><li>它们不会做出突然的、把人吓一跳的动作</li><li>它们对人类不感兴趣</li><li>它们很搞笑</li></ul><p>例子:</p><p><strong>尺蠖</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/inchworm.jpg" target="_blank" rel="noreferrer"><img src="'+v+'" alt="Source"></a></p><p><a href="https://karen-lifeactually.blogspot.com/2012/05/inchworm-life-cycle.html" target="_blank" rel="noreferrer">来源</a></p><p>尺蠖就是理想中的滑稽虫。荒谬、萌、动作慢、还有点书呆子气。是少数几种我一点都不介意用手碰的虫子之一。</p><p><strong>瓢虫</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/Ladybug.jpg" target="_blank" rel="noreferrer"><img src="'+j+'" alt="Source"></a></p><p><a href="https://upload.wikimedia.org/wikipedia/commons/d/de/BIEDRONA.JPG" target="_blank" rel="noreferrer">来源</a></p><p>瓢虫其实是在耍我们。如果它们是黑色的,我们才不会喜欢它们。它们就会变成恶心的小甲虫。可人类是最容易糊弄的观众,穿得像个小丑就足以让人类喜欢上它们。它们身上一大污点是——它们会毫无预兆地飞起来,有把人吓一跳的潜力,而我总是忘了它们其实会飞。</p><p><strong>西瓜虫</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/ball-beetle.jpg" target="_blank" rel="noreferrer"><img src="'+S+'" alt="Pill bug"></a></p><p>欺负西瓜虫 (pill bug) 特别好玩。你只要碰它一下,它就进入紧急模式,蜷成一个硬硬的小球,你可以用手指把它推来推去。然后你一停手,它得等几秒钟才鼓起勇气重新展开、继续过自己的日子,这时你就可以再重复一遍。顺便说一句,这也是一种恶心的小虫,它靠这个缩球把戏分散我们对它真面目的注意力,硬是混进了「傻乎乎」这个类别。</p><p>而且它其实不是昆虫,而是甲壳动物,这事我刚刚才知道,但我已经写完了,所以就这么留着吧!</p><p><strong>毛毛虫 (The Caterpillar)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/monarch-caterpillar1.jpeg" target="_blank" rel="noreferrer"><img src="'+x+'" alt="Caterpillar"></a></p><p>毛毛虫是种挺逗的、自我厌弃的小生物,老是一副闷闷不乐的样子。它们慢得离谱,所以一点也不吓人 (通常是这样,<a href="http://weirdthings.com/wp-content/uploads/2012/02/skitched-20120202-163637.jpg" target="_blank" rel="noreferrer">也不是绝对</a>),而且一般都待在户外。</p><p>通常来说,体型大是「傻乎乎」这一类的硬伤,但毛毛虫哪怕长得挺大,也能靠彻底像个卡通形象来保持不吓人。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/aliens_bugs_04.jpg" target="_blank" rel="noreferrer"><img src="'+q+'" alt="Large green caterpillar"></a></p><p><strong>蝴蝶 (The Butterfly)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/Viceroy_Butterfly.jpg" target="_blank" rel="noreferrer"><img src="'+B+'" alt="Source"></a></p><p><a href="https://en.wikipedia.org/wiki/File:Viceroy_Butterfly.jpg" target="_blank" rel="noreferrer">图片来源</a></p><p>蝴蝶按理说应该很吓人——一只巨大的、会飞的昆虫!但它其他方面基本都做对了,于是就莫名地成立了——它们漂亮、温柔、总是在户外,而且它们扇翅膀不像大多数昆虫那样让人紧张、嗡嗡作响,而是轻盈优雅的。蝴蝶和瓢虫、萤火虫一起,组成了五岁小女孩最喜爱的三大昆虫组合。</p><p>我还是最近才知道,毛毛虫在茧里并不是「在身体上长出翅膀」,而是把整个身体溶解成一坨细胞糊,然后再重新组合成一只蝴蝶。不确定这到底是那种「大家都知道就我不知道」的事,还是很多人也是刚听说。</p><p><strong>讨厌的昆虫 (Unpleasant Insects)</strong></p><p>「讨厌的昆虫」指的是那些其实基本无害、但长相和行为都像那种让人不爽的昆虫,而且不像「傻乎乎昆虫」那伙人还有点小噱头来遮掩。它们不会毁掉我的生活,但它们要是不存在,世界还是会更美好一些。</p><p><strong>蚱蜢 (The Grasshopper)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/grasshopper-1.jpg" target="_blank" rel="noreferrer"><img src="'+A+'" alt="Source"></a></p><p><a href="http://wordnuggets.wordpress.com/2011/02/03/grasshoppers-giants-nephilim/" target="_blank" rel="noreferrer">图片来源</a></p><p>蚱蜢过于神经质、动不动就蹦跶,实在算不上讨喜。但它们对人类或人类的家一般不感兴趣,所以放在第二类正合适。</p><p><strong>家蝇</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/Housefly_white_background02.jpg" target="_blank" rel="noreferrer"><img src="'+T+'" alt="Source"></a></p><p><a href="https://commons.wikimedia.org/wiki/File:Housefly_white_background02.jpg" target="_blank" rel="noreferrer">Source</a></p><p>家蝇 (Housefly) 并不讨人喜欢。它们丑陋、不友好,而且名字里带个「家」字,就是因为它们特别喜欢跟你待在同一个屋子里。它们还偷吃你的食物,而且我最近发现,当它们落在食物上几秒钟一动不动的时候,是因为它们在往食物上吐,把唾液吐在它们准备吃的那一块上,提前启动消化过程(这就是那种你知道了反倒不如不知道的知识——抱歉了)。</p><p>它们最大的加分项,也是被放进这一类的原因,就是它们不像很多别的虫子那样让我起鸡皮疙瘩。我不是<em>怕</em>家蝇,只是嫌它们烦。</p><p><strong>蚂蚁</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/ants.jpg" target="_blank" rel="noreferrer"><img src="'+I+'" alt="Source"></a></p><p><a href="http://www.alexanderwild.com/Ants/Taxonomic-List-of-Ant-Genera/Linepithema/i-xS23CSp/A" target="_blank" rel="noreferrer">Source</a></p><p>当有人家里出现一大群蚂蚁的时候,我觉得人们会以为每只蚂蚁都是自己闻到了面包屑然后一起赶来的。但实际上,蚂蚁的运作方式是:<em>一只</em>讨厌的蚂蚁跑来探险,发现了面包屑,然后回去<em>告诉了其他蚂蚁</em>。所以如果你在厨房里看到一只落单的蚂蚁在溜达,趁它还没把「我发现了个厨房」的消息告诉另外 1000 只蚂蚁之前,先把它这小小的生命终结了吧。</p><p>虽然普通的黑蚂蚁放在这个相对无害的类别里挺合适,但世上还有其他远远更可怕的蚂蚁。以及某些完全丧心病狂的人,他们把蚂蚁用于<a href="https://www.youtube.com/watch?v=9WQ6rFKhyn0" target="_blank" rel="noreferrer"><em>不可言说的</em>仪式</a>。</p><p><strong>蜜蜂</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/honeybee.jpg" target="_blank" rel="noreferrer"><img src="'+L+'" alt="Source"></a></p><p><a href="http://www.beeswarm.co.uk/bee-swarm-or-not/" target="_blank" rel="noreferrer">Source</a></p><p>蜜蜂 (Honeybee) 的可怕程度被高估了。对于一个几乎怕所有虫子的人来说,蜜蜂从来没让我烦恼过。对付蜜蜂——甚至它们那些更让人不爽的亲戚比如黄蜂和大黄蜂——的关键,就是把它们的行事逻辑内化于心:它们<em>懒得搭理</em>人类,没有动机蜇你,只要你不理它们,啥事儿都不会发生。蜜蜂唯一变成混蛋的时候,就是它感到受威胁——而这只在你看到它就抓狂时才会发生。我还特别享受跟别人在一起、周围又有蜜蜂的时候,因为这是我<em>唯一</em>能表现得像个成年人的昆虫。</p><p>如果你感兴趣,<a href="https://www.youtube.com/watch?v=JDSf3Kshq1M" target="_blank" rel="noreferrer">这里有段视频</a>,是大黄蜂在干坏事。</p><p><strong>令人不安的昆虫</strong></p><p>让人心烦的昆虫不只是讨厌——它们是在主动把生活搞得更糟。从现在开始,谁要是对这些昆虫表现得一副无所谓的样子,我就烦得要死,因为这些昆虫明摆着就是烦人,你到底有什么毛病。</p><p><strong>飞蛾</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/Moth.jpg" target="_blank" rel="noreferrer"><img src="'+R+'" alt="Source"></a></p><p><a href="http://www.warrenphotographic.co.uk/13851-november-moth" target="_blank" rel="noreferrer">Source</a></p><p>我讨厌飞蛾——蝴蝶那恶心又让人焦虑的表亲。你知道蝴蝶不会做什么吗?它们不会干这种破事:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/moths-on-light.jpg" target="_blank" rel="noreferrer"><img src="'+C+'" alt="Source"></a></p><p><a href="http://www.huntercourse.com/blog/2011/09/debunking-rumors-about-weird-hunting-laws/" target="_blank" rel="noreferrer">Source</a></p><p>也不会干这种:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/lots-moths.jpg" target="_blank" rel="noreferrer"><img src="'+H+'" alt="Source"></a></p><p><a href="http://my.opera.com/quentinscrisp/blog/death-by-toothpaste" target="_blank" rel="noreferrer">Source</a></p><p>这行为真是让人无比反感。还有,飞蛾这也太不合逻辑了吧——它们对光<strong>痴迷</strong>到心无旁骛,却又是夜行动物?飞蛾界到底是谁做的这个决定,这人怎么这么不靠谱?</p><p><strong>大蚊子</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/Large-Mosquito.jpg" target="_blank" rel="noreferrer"><img src="'+W+'" alt="Source"></a></p><p><a href="https://mullumyard.blogspot.com/2011/07/mystery-insect.html" target="_blank" rel="noreferrer">Source</a></p><p>完全搞不懂大蚊子是个什么状况,也搞不懂它这辈子在忙活什么。小蚊子们都在外面好好地干正事、摧毁快乐,这个怪咖却在天花板角落里瞎折腾。就好像一只体型是普通蚊子 10 倍、智商是普通蚊子 1/10 的蚊子。</p><p><strong>果蝇</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/fruit-flies.jpg" target="_blank" rel="noreferrer"><img src="'+D+'" alt="Source"></a></p><p><a href="http://www.snailtail.com/" target="_blank" rel="noreferrer">Source</a></p><p>周一,两只果蝇。周二,三只果蝇。周三,880 只果蝇。</p><p><strong>烦人的蜘蛛</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/spider1.jpg" target="_blank" rel="noreferrer"><img src="'+E+'" alt="Source"></a></p><p><a href="http://www.hollyanissa.com/2011/06/21/oh-so-sweet-a-new-lens-and-a-new-love/" target="_blank" rel="noreferrer">Source</a></p><p><img src="'+P+'" alt="Daddy Long Legs"></p><p><a href="http://bindingofisaac.wikia.com/wiki/File:Daddy_long_legs_lrg.jpg" target="_blank" rel="noreferrer"></a>不要跟噩梦级蜘蛛搞混了,烦人的蜘蛛涵盖的是那些没那么吓人的种类,从超小的那种到荒唐至极的盲蛛 (Daddy Longlegs) 都算。</p><p>另一种让我抓狂的人是那种会说「你应该让家里的蜘蛛活下来,因为它们会吃掉别的虫子」的人。抱歉,不,我才不要自愿和怪物同住,就因为它们运气好的时候可能会杀掉另一只怪物。你以为你是谁——1750 年的女巫吗?我们已经发明了各种先进的除虫手段,你居然放着现代方法不用,选择把<em>一个昆虫的巢穴</em>当作你居住环境的一部分?</p><p>和蜘蛛同住还意味着有时候你走进一个房间,忽然脸上就挂着一缕蜘蛛丝。这种时候,你知道三件事:1) 附近某处一定有只蜘蛛,2) 它可能就在你头发里或者衣领里,3) 你的脸上正糊着刚从蜘蛛屁股里出来的东西。</p><p><strong>完全无法接受的昆虫</strong></p><p>我们已经聊过一些坏角色了,但到目前为止,还没有一个是<em>以你的身体为食</em>的。现在我们要说到一批携带疾病的怪物,它们的目标就是落在你皮肤上、<em>钻进去</em>、喝你的血。这<em>不行</em>。这里头没有任何一部分是可以接受的。</p><p><strong>蚊子</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/mosquito.jpg" target="_blank" rel="noreferrer"><img src="'+V+'" alt="Source"></a></p><p><a href="http://www.umaa.org/" target="_blank" rel="noreferrer">Source</a></p><p>在充满各种或好或坏经历的人生中,最糟糕的一件事就是黑暗中躺在床上,听见蚊子在耳边发出的高频嗡嗡声。一只飞行怪物就在离你两英寸的地方,打算整晚咬你的脸。你朝着声音的方向挥手,声音停了——这意味着要么 A) 它停在了一英尺外的某个表面上按兵不动,要么 B) 它就落在你脑袋的某个位置,而你毫无察觉。就算你能撑过这一关,大约 30 秒后,嗡嗡声又来了。你再挥手,声音又停了。</p><p>这个循环一遍又一遍地重复,最终以两种结局之一收场:</p><ol><li><p>你终于睡着了,然后它降落在你脸上,<em>整晚吸你脸上的血</em>。</p></li><li><p>你他妈爬下床,打开灯,穿着内裤拿着一本杂志在屋里转圈,想转多久转多久,直到把蚊子拍死为止。</p></li></ol><p><em>相当一部分人</em>居然不去选择结局 2,这我实在无法理解。凭什么结局 1 对任何人来说都能接受??</p><p><strong>蜱虫</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/dick.jpg" target="_blank" rel="noreferrer"><img src="'+F+'" alt="Source"></a></p><p><a href="http://www.tickinfo.com/" target="_blank" rel="noreferrer">Source</a></p><p>哦,不过就是一种从树上掉到你身上、或者从草丛里跳到你身上,然后悄悄地把脑袋和身体深深钻进你皮肤里的虫子。然后你要是发现了它们、请它们离开,<em>它们死活不肯松口。</em> 还有比这更让人反胃的行为吗?谁把它们养成这样的?作为额外福利,它们还终身携带莱姆病 (Lyme Disease),等你终于把它们的头从身体上切下来、说服它们去追求别的人生目标时,顺便把病也留给了你。</p><p><strong>虱子 (The Louse)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/louse.jpg" target="_blank" rel="noreferrer"><img src="'+G+'" alt="Source"></a></p><p><a href="https://en.wikipedia.org/wiki/Head_louse" target="_blank" rel="noreferrer">Source</a></p><p>我上小学的时候,校医会把每个人叫到办公室做虱子检查,我当时压根没当回事。我以为就跟检查头皮屑之类的差不多。直到有一天我看到了一张长这样的照片,才意识到虱子到底是个什么玩意儿。</p><p>那是自从我看《芝麻街》(Sesame Street) 一段挤牛奶的节目、意识到牛奶并不是来自某种白色瀑布或奶油云朵、而是从奶牛<a href="http://philip.greenspun.com/images/pcd4554/cow-udder-45.4.jpg" target="_blank" rel="noreferrer">青筋暴突的下腹肉柱</a>上伸出的肉手指里挤出来的、从而在六岁那年永久终结了我喝牛奶的日子以来,最令我恐惧的一次发现。</p><p>看了上面那张照片,我实在搞不懂为什么小孩子还非要在什么&quot;床底下的怪物&quot;这种老掉牙的恐惧上发挥想象力,毕竟<em>真的</em>怪物可能就住在<em>他们脑袋上</em>啊。</p><p>我现在还在纳闷,为什么我在 5 岁到 13 岁之间被查了大概 40 次虱子,之后就再也没查过了。这事儿好像也没怎么想明白。</p><p><strong>臭虫 (The Bedbug)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/bed-bugs.jpg" target="_blank" rel="noreferrer"><img src="'+J+'" alt="Source"></a></p><p><a href="http://www.nydailynews.com/news/national/chicago-top-city-bedbugs-article-1.1242786" target="_blank" rel="noreferrer">Source</a></p><p>搬家,东西全部换新。这个话题到此为止,再也别提了。</p><p><strong>噩梦级昆虫</strong></p><p>鉴于虫子就是这副德性,这最后一个黑暗类别其实可以纳入相当多的生物,<a href="http://folksong.org.nz/wottenwood_weta/giantweta.jpg" target="_blank" rel="noreferrer">比如</a> <a href="https://1.bp.blogspot.com/-qp8uqK9JUDY/T3b-Vp32rJI/AAAAAAAABFU/ldehSSp-wAk/s1600/Giant%2Bpalm%2Bkatydid%2Bsmall.jpg" target="_blank" rel="noreferrer">这</a> <a href="http://www.mnn.com/sites/default/files/styles/node-gallery-display/public/titanbeetle.jpg" target="_blank" rel="noreferrer">三</a>位。但既然你我今天迟早还得干点别的事,我就只讲最出名的几种噩梦级昆虫。先从我们都能达成共识的、这世上最糟糕的生物开始——</p><p><strong>蟑螂 (The Cockroach)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/Cockroaches1.jpg" target="_blank" rel="noreferrer"><img src="'+M+'" alt="Cockroaches"></a></p><p><a href="http://albitechpest.com/cockroaches.html" target="_blank" rel="noreferrer">Source</a></p><p>我现在有一种特别的感觉。就是那种你本来在找蟑螂的图片,结果不知道为什么鬼使神差地在谷歌上搜了「蟑螂成灾」并看图片的感觉。我不推荐你这么做,但如果你想理解我现在的感受,你可以试试。</p><p>为了尽力找回自我,我要往下讲——我在找照片时还确认了一件事:美洲大蠊——最大的那种蟑螂——是真的会飞。</p><p>也许是这条新知识——或者是我房东跟我说过的话让我印象太深,他说纽约市的每一栋楼都有蟑螂,就算你公寓里没有,墙里和锅炉房里也肯定有——又或者是不到六个月前的那件事:我在洛杉矶的办公室里加班,穿着人字拖,突然感觉脚上有东西,低头一看,一只巨大的蟑螂正趴在我光着的脚背上,而我到现在都还没完全缓过来——反正我身体里有种什么东西已经非常准备好进入下一种虫子了。</p><p>小插曲:我刚才看到手腕上有一小片沙发上的绒毛,<em>猛地一激灵</em>,因为写这篇文章已经把我搞得神经紧绷。希望接下来能有点更愉快的东西。</p><p><strong>蜈蚣</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/centipede.jpg" target="_blank" rel="noreferrer"><img src="'+U+'" alt="Source"></a></p><p><a href="http://www.whatsthatbug.com/2009/11/07/house-centipede-32/" target="_blank" rel="noreferrer">Source</a></p><p>算了吧那些「留着你的蜘蛛」的人。我从上面拿这张图的那个<a href="http://www.whatsthatbug.com/2009/11/07/house-centipede-32/" target="_blank" rel="noreferrer">网站</a>专门给关于虫子的建议,他们对这只<em>科幻恐怖片外星人</em>是这么说的:</p><blockquote><p><em>Brandon 标记为「末日虫」的这位,其实是一只无害、有益的家居蜈蚣。这种夜行掠食者不会咬人,灯一开就会跑掉,如果你不去管它,它还会吃掉蟑螂和其他你不想要的家庭入侵者。</em></p></blockquote><p>我能想到最贴切的类比是:一个女人报警,说她厨房台面上蹲着一个赤身裸体的男人正扭曲地笑着盯着她,警察告诉她别管那个男人,因为他只是盯着看,估计不会碰她,而且万一有窃贼、强奸犯或杀人犯闯进来,他们看到台面上蹲着一个裸体傻笑的男人肯定会被吓到,转头就走,不会伤害她。</p><p><strong>噩梦级蜘蛛</strong></p><p>轮到万物痛苦之王登场了。可怕的虫子有很多,但没有一个能给我那种感觉——就是当我坐在沙发上,一转头看向台灯,然后看见这个的感觉:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/spider-on-lamp.jpg" target="_blank" rel="noreferrer"><img src="'+N+'" alt="Source"></a></p><p><a href="http://www.survivalistboards.com/showthread.php?t=102657&amp;page=2" target="_blank" rel="noreferrer">Source</a></p><p>蜘蛛就是跟其他虫子不一样——它们自成一档,恐怖等级比前面两种生物高出好几个段位。而且我们现在已经离开「非理性恐惧」的地界了——灯上那家伙快得离谱,还会跳,咬一口没准能要你的命。这次是有实打实的理由害怕的。</p><p>看着那张照片我脑子里只有一个念头:接下来我他妈到底该怎么办。我大概会慢慢把台灯端到屋外去,但很有可能你刚一动灯,它就开始绕着灯罩狂奔,或者直接跳下来,然后你就体验到这种场面:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/1277193438_huge-spider-on-the-ceiling.gif" target="_blank" rel="noreferrer"><img src="'+O+'" alt="Spider GIF"></a></p><p>抱歉,我知道我现在让你受了不少罪。快结束了。</p><p>我们愉快地开始收尾吧,先来一张<em>大到能吃鸟的蜘蛛</em></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/spider-bird.jpg" target="_blank" rel="noreferrer"><img src="'+$+'" alt="Source"></a></p><p><a href="http://www.telegraph.co.uk/earth/earthnews/3353693/Giant-spider-eating-a-bird-caught-on-camera.html" target="_blank" rel="noreferrer">Source</a></p><p>最后,人类历史上拍到过的最恐怖的一张照片——<em>一只狼蛛和它几百个狼蛛宝宝。</em></p><h2 id="" tabindex="-1"><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/spider_ceiling-700252.jpg" target="_blank" rel="noreferrer"><img src="'+K+'" alt="Source"></a> <a class="header-anchor" href="#" aria-label="Permalink to &quot;[![Source](/images/why-bugs-ruin-everything/spider_ceiling-700252-600x480.jpg)](https://waitbutwhy.com/wp-content/uploads/2014/02/spider_ceiling-700252.jpg)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的 <strong><a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a></strong>,新文章发布时我们会通知你。</p><p>如果想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><p><strong>______</strong></p><p><strong>三篇不那么让人不安的 Wait But Why 动物剖析:</strong></p><p><a href="https://waitbutwhy.com/2013/08/the-bunny-manifesto.html" target="_blank" rel="noreferrer">兔子宣言</a><br><a href="https://waitbutwhy.com/2013/10/the-primate-awards.html" target="_blank" rel="noreferrer">灵长类大奖<br></a><a href="https://waitbutwhy.com/2014/10/dark-secrets-bird-world.html" target="_blank" rel="noreferrer">鸟类世界的黑暗秘密</a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/Animated0204.gif" target="_blank" rel="noreferrer"><img src="'+Z+'" alt="Bugs ruin life"></a></p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/02/why-bugs-ruin-everything.html&amp;description=Why%20Bugs%20Ruin%20Everything" target="_blank" rel="noreferrer"><img src="'+z+'" alt=""></a></p>',188)])])}const nr=t(Q,[["render",Y]]);export{or as __pageData,nr as default};
